    {
      "role": "User",
      "gender": "female",
      "position": "center foreground",
      "expression": "subtle closed-mouth smile",
      "interaction": "being playfully pinched on the cheeks"
    },
    {
      "role": "Dua Lipa",
      "gender": "female",
      "position": "right side of the frame",
      "expression": "smiling",
      "interaction": "playfully pinching the user’s other cheek"
